    relatedCandySlugs: ['bubs-watermelon', 'bubs-sour-skulls', 'saltlakrits', 'marabou-mjolkchoklad', 'daim', 'plopp', 'kexchoklad', 'lakerol', 's-marke-supersurt', 'ahlgrens-bilar'],
