// Helper functions
export function getArticleBySlug(slug: string): Article | undefined {
  return articles.find((a) => a.slug === slug)
}

export function getAllArticleSlugs(): string[] {
  return articles.filter((a) => a.status === 'published').map((a) => a.slug)
}

export function getPublishedArticles(): Article[] {
  return articles.filter((a) => a.status === 'published')
}

export function getArticlesBySilo(silo: Article['silo']): Article[] {
  return articles.filter((a) => a.silo === silo)
}

export function getRelatedArticles(slug: string, limit = 4): Article[] {
  const article = getArticleBySlug(slug)
  if (!article) return []
  return articles
    .filter((a) => article.relatedArticleSlugs.includes(a.slug))
    .slice(0, limit)
}

export function getArticlesForCandy(candySlug: string, limit = 3): Article[] {
  return articles
    .filter((a) => a.status === 'published' && a.relatedCandySlugs.includes(candySlug) && a.content.trim().length > 100)
    .sort((a, b) => {
      // Prioritize P1 > P2 > P3, then by content length (deeper articles first)
      const priorityOrder = { P1: 0, P2: 1, P3: 2 }
      const pDiff = (priorityOrder[a.priority] || 2) - (priorityOrder[b.priority] || 2)
      if (pDiff !== 0) return pDiff
      return b.content.length - a.content.length
    })
    .slice(0, limit)
}
